CustomField.formula:
TEXT(Account_Catalyst_Health_Score__c)&" "&
IF( 
				Account_Catalyst_Health_Score__c > 8, IMAGE("/servlet/servlet.FileDownload?file=0150O000004xFo5", "green", 16, 50 ),
				IF(
							Account_Catalyst_Health_Score__c > 4, IMAGE("/servlet/servlet.FileDownload?file=0150O000004xWeC", "yellow", 16, 50 ),
							IF(
											Account_Catalyst_Health_Score__c > 0, IMAGE("/servlet/servlet.FileDownload?file=0150O000004xFpH", "red" , 16, 50), NULL
											)
							)
				)
